<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;turns&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // increase from default 4 to 8</span></span>
